Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
[TestClass]
public sealed class PlatformTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public PlatformTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only: skipped on other OSes
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_UsesGpuAcceleration()
    {
        var result = GpuRenderer.RenderFrame();
        Assert.IsTrue(result.WasHardwareAccelerated);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await WeatherClient.GetForecastAsync(
            "Seattle", _testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Cleanup temp files even on failure
    [TestMethod]
    public void Export_CreatesValidFile()
    {
        _tempFile = Path.GetTempFileName();
        Exporter.WriteTo(_tempFile);
        Assert.IsNotEmpty(File.ReadAllText(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Key takeaways:**

| Scenario | Solution |
|----------|----------|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` — skips (not fails) on other OSes |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` — skips when CI env vars are detected |
| Flaky external API | `[Retry(3)]` — retries up to 3 times before reporting failure |
| Cleanup on failure | `[TestCleanup]` — always runs after the test, even if it throws |

All four attributes require **MSTest 3.9+** (Retry) or **3.10+** (OSCondition/CICondition). Pair `[Retry]` with `[Timeout]` to avoid hanging indefinitely on a stuck external call.
